using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class ConstructorTests
{
    [TestMethod]
    public void DefaultThreshold_Is10()
    {
        var tracker = new InventoryTracker();
        Assert.AreEqual(10, tracker.ReorderThreshold);
    }

    [TestMethod]
    public void CustomThreshold_IsStored()
    {
        var tracker = new InventoryTracker(reorderThreshold: 25);
        Assert.AreEqual(25, tracker.ReorderThreshold);
    }

    [TestMethod]
    public void ZeroThreshold_IsAllowed()
    {
        var tracker = new InventoryTracker(reorderThreshold: 0);
        Assert.AreEqual(0, tracker.ReorderThreshold);
    }

    [TestMethod]
    public void NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => new InventoryTracker(reorderThreshold: -1));
    }
}

[TestClass]
public class GetStockLevelTests
{
    [TestMethod]
    public void UnknownSku_ReturnsZero()
    {
        var tracker = new InventoryTracker();
        Assert.AreEqual(0, tracker.GetStockLevel("UNKNOWN-001"));
    }

    [TestMethod]
    public void AfterAddStock_ReturnsCorrectLevel()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 50);
        Assert.AreEqual(50, tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void InvalidSku_Throws(string? sku)
    {
        var tracker = new InventoryTracker();
        Assert.ThrowsException<ArgumentException>(() => tracker.GetStockLevel(sku!));
    }
}

[TestClass]
public class AddStockTests
{
    [TestMethod]
    public void AddOnce_SetsLevel()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 20);
        Assert.AreEqual(20, tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddMultipleTimes_Accumulates()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 10);
        tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void DifferentSkus_TrackedIndependently()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 10);
        tracker.AddStock("SKU-B", 30);

        Assert.AreEqual(10, tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(30, tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void NonPositiveQuantity_Throws(int quantity)
    {
        var tracker = new InventoryTracker();
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => tracker.AddStock("SKU-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void InvalidSku_Throws(string? sku)
    {
        var tracker = new InventoryTracker();
        Assert.ThrowsException<ArgumentException>(() => tracker.AddStock(sku!, 5));
    }
}

[TestClass]
public class RemoveStockTests
{
    [TestMethod]
    public void RemovePartial_ReducesLevel()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 50);
        tracker.RemoveStock("SKU-A", 20);
        Assert.AreEqual(30, tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveAll_LevelBecomesZero()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 10);
        tracker.RemoveStock("SKU-A", 10);
        Assert.AreEqual(0, tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveMoreThanAvailable_Throws()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 5);

        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => tracker.RemoveStock("SKU-A", 10));

        StringAssert.Contains(ex.Message, "Insufficient stock");
    }

    [TestMethod]
    public void RemoveFromUnknownSku_Throws()
    {
        var tracker = new InventoryTracker();

        Assert.ThrowsException<InvalidOperationException>(
            () => tracker.RemoveStock("GHOST", 1));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-3)]
    public void NonPositiveQuantity_Throws(int quantity)
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 50);

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => tracker.RemoveStock("SKU-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void InvalidSku_Throws(string? sku)
    {
        var tracker = new InventoryTracker();
        Assert.ThrowsException<ArgumentException>(() => tracker.RemoveStock(sku!, 1));
    }
}

[TestClass]
public class NeedsReorderTests
{
    [TestMethod]
    public void StockAboveThreshold_ReturnsFalse()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-A", 50);
        Assert.IsFalse(tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void StockAtThreshold_ReturnsTrue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-A", 10);
        Assert.IsTrue(tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void StockBelowThreshold_ReturnsTrue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-A", 3);
        Assert.IsTrue(tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void UnknownSku_ReturnsTrue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 5);
        Assert.IsTrue(tracker.NeedsReorder("UNKNOWN"));
    }

    [TestMethod]
    public void ZeroThreshold_OnlyZeroStockNeedsReorder()
    {
        var tracker = new InventoryTracker(reorderThreshold: 0);
        tracker.AddStock("SKU-A", 1);
        Assert.IsFalse(tracker.NeedsReorder("SKU-A"));

        tracker.RemoveStock("SKU-A", 1);
        Assert.IsTrue(tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void AfterRemoval_ReorderStatusUpdates()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-A", 20);
        Assert.IsFalse(tracker.NeedsReorder("SKU-A"));

        tracker.RemoveStock("SKU-A", 15);
        Assert.IsTrue(tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void InvalidSku_Throws(string? sku)
    {
        var tracker = new InventoryTracker();
        Assert.ThrowsException<ArgumentException>(() => tracker.NeedsReorder(sku!));
    }
}

[TestClass]
public class TransferStockTests
{
    [TestMethod]
    public void Transfer_DeductsFromSourceAddsToDestination()
    {
        var source = new InventoryTracker();
        var dest = new InventoryTracker();

        source.AddStock("SKU-A", 100);
        source.TransferStock("SKU-A", 40, dest);

        Assert.AreEqual(60, source.GetStockLevel("SKU-A"));
        Assert.AreEqual(40, dest.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferAll_SourceBecomesZero()
    {
        var source = new InventoryTracker();
        var dest = new InventoryTracker();

        source.AddStock("SKU-A", 25);
        source.TransferStock("SKU-A", 25, dest);

        Assert.AreEqual(0, source.GetStockLevel("SKU-A"));
        Assert.AreEqual(25, dest.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferToDestinationWithExistingStock_Accumulates()
    {
        var source = new InventoryTracker();
        var dest = new InventoryTracker();

        source.AddStock("SKU-A", 50);
        dest.AddStock("SKU-A", 20);
        source.TransferStock("SKU-A", 30, dest);

        Assert.AreEqual(20, source.GetStockLevel("SKU-A"));
        Assert.AreEqual(50, dest.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferMoreThanAvailable_Throws_SourceUnchanged()
    {
        var source = new InventoryTracker();
        var dest = new InventoryTracker();

        source.AddStock("SKU-A", 10);

        Assert.ThrowsException<InvalidOperationException>(
            () => source.TransferStock("SKU-A", 50, dest));

        // Source must remain unchanged after a failed transfer
        Assert.AreEqual(10, source.GetStockLevel("SKU-A"));
        Assert.AreEqual(0, dest.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferToSelf_Throws()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 30);

        Assert.ThrowsException<InvalidOperationException>(
            () => tracker.TransferStock("SKU-A", 10, tracker));
    }

    [TestMethod]
    public void NullDestination_Throws()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 10);

        Assert.ThrowsException<ArgumentNullException>(
            () => tracker.TransferStock("SKU-A", 5, null!));
    }

    [TestMethod]
    public void MultipleTransfersBetweenWarehouses()
    {
        var warehouseA = new InventoryTracker();
        var warehouseB = new InventoryTracker();
        var warehouseC = new InventoryTracker();

        warehouseA.AddStock("SKU-X", 100);

