             () => tracker.TransferStock("SKU-A", 10, tracker));
     }

     [TestMethod]
     public void NullDestination_Throws()
     {
         var tracker = new InventoryTracker();
         tracker.AddStock("SKU-A", 10);

         Assert.ThrowsExactly<ArgumentNullException>(
             () => tracker.TransferStock("SKU-A", 5, null!));
     }

     [TestMethod]
     public void MultipleTransfersBetweenWarehouses()
     {
         var warehouseA = new InventoryTracker();
         var warehouseB = new InventoryTracker();
         var warehouseC = new InventoryTracker();

         warehouseA.AddStock("SKU-X", 100);

         warehouseA.TransferStock("SKU-X", 40, warehouseB);
         warehouseB.TransferStock("SKU-X", 15, warehouseC);

         Assert.AreEqual(60, warehouseA.GetStockLevel("SKU-X"));
         Assert.AreEqual(25, warehouseB.GetStockLevel("SKU-X"));
         Assert.AreEqual(15, warehouseC.GetStockLevel("SKU-X"));
     }

     [TestMethod]
     public void TransferTriggersReorderOnSource()
     {
         var source = new InventoryTracker(reorderThreshold: 10);
         var dest = new InventoryTracker();

         source.AddStock("SKU-A", 20);
         Assert.IsFalse(source.NeedsReorder("SKU-A"));

         source.TransferStock("SKU-A", 15, dest);
         Assert.IsTrue(source.NeedsReorder("SKU-A"));
     }
 }

